constraint.pattern:
Services phải sử dụng environment flag để switch giữa real API và mock:
if (environment.useMocks) return of(MOCK_DATA);
else return this.http.get(url);

rule.template:
@Component({
  selector: 'app-{name}',
  standalone: true,
  imports: [CommonModule, RouterModule, /* specific imports only */],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `...`,
})
export class {Name}Component { }

export class {Name}Component {
  // State signals
  protected readonly posts = signal<Post[]>([]);
  protected readonly isLoading = signal(false);
  protected readonly error = signal<string | null>(null);

  // Computed signals
  protected readonly hasPosts = computed(() => this.posts().length > 0);
  protected readonly filteredPosts = computed(() =>
    this.posts().filter(p => p.isPublic)
  );

  // Effect for side effects
  constructor() {
    effect(() => {
      if (this.error()) console.error(this.error());
    });
  }
}

@Injectable({ providedIn: 'root' })
export class {Domain}Service {
  private readonly http = inject(HttpClient);
  private readonly apiUrl = inject(API_URL_TOKEN);

  get{Resources}(params: {Resource}QueryParams): Observable<PaginatedResponse<{Resource}>> {
    return this.http.get<PaginatedResponse<{Resource}>>(
      `${this.apiUrl}/api/v1/{resources}`,
      { params: params as Record<string, string> }
    );
  }
}
